//! emit-wire-hex — Rust bin that emits a known wire blob as hex to stdout.
//!
//! Used by scripts/cross-lang-wire-fixture.ts to verify the Rust encoder
//! and TS decoder agree byte-for-byte on the wire format.
//!
//! Usage:
//!   cargo run --release --bin emit-wire-hex
//!
//! Stdout: hex string (no whitespace, no newline).

use distributed_inference::amplituhedron_wire::{
    encode_replay_response, AmplituhedronReplayBinary,
};

fn main() {
    // Deterministic fixture: 3584 f32 values from a small LCG
    let hidden_dim: usize = 3584;
    let mut state: u64 = 0xCAFEBEEF;
    let mut residual: Vec<f32> = Vec::with_capacity(hidden_dim);
    for _ in 0..hidden_dim {
        state = state
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let u = (state >> 32) as u32;
        residual.push(u as f32 / u32::MAX as f32);
    }

    let reply = AmplituhedronReplayBinary {
        hit: true,
        tail_len: residual.len() as u32,
        kv_slab_len: 0,
        tail_residual: Some(residual),
    };

    let bytes = encode_replay_response(&reply);
    let hex: String = bytes.iter().map(|b| format!("{:02x}", b)).collect();
    print!("{}", hex);
}
